using QBEngineer.Core.Entities;
using QBEngineer.Core.Enums;
using QBEngineer.Data.Context;

using Serilog;

namespace QBEngineer.Api.Data.TrainingContent;

public class CustomerReturnsTraining : TrainingContentBase
{
    public CustomerReturnsTraining(AppDbContext db, Dictionary<string, int> slugMap) : base(db, slugMap) { }

    public override async Task SeedAsync()
    {
        // ── Overview (Article) ───────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Customer Returns Overview",
            Slug = "customer-returns-overview",
            Summary = "What customer returns (RMAs) are, the return lifecycle from Received to Closed, and how returns connect to sales orders, jobs, and inventory.",
            ContentType = TrainingContentType.Article,
            EstimatedMinutes = 4,
            IsPublished = true,
            SortOrder = 1,
            AppRoutes = """["/sales-orders"]""",
            Tags = """["customer-returns","sales"]""",
            ContentJson = """{"body":"## Customer Returns Overview\n\nThe Customer Returns module tracks returned goods from customers through a structured RMA (Return Merchandise Authorization) lifecycle. Every return is linked to the original job that produced the goods and optionally to a rework job created to correct the issue.\n\n### What Is a Customer Return?\n\nA customer return represents goods sent back by a customer due to defects, incorrect specifications, damage during shipping, or other quality issues. Each return is assigned a unique RMA number (e.g., RMA-00001) and tracked through a series of statuses until the issue is fully resolved and closed.\n\n### The Return Lifecycle\n\nCustomer returns move through five statuses in a defined order:\n\n1. **Received** — The return has been logged in the system. The customer's goods have arrived back at your facility. This is the initial status when a return is created.\n2. **Under Inspection** — The returned goods are being inspected to determine the root cause of the issue. An inspector is assigned and inspection notes are recorded.\n3. **Rework Ordered** — A rework job has been created to correct the defect. The rework job appears on the Kanban board and follows the normal production workflow. The return automatically moves to this status when a rework job is generated during creation.\n4. **Resolved** — The issue has been addressed — either through rework, replacement, credit, or other corrective action. The return can be resolved via the resolve endpoint once the corrective action is complete.\n5. **Closed** — Final status. The return is fully processed and closed out. Only resolved returns can be closed. Closed returns cannot be reopened or modified.\n\n### How Returns Connect to Other Features\n\n**Jobs:** Every return links to the original job that produced the returned goods via the OriginalJobId field. When a rework job is created, it links back to the return and also creates a RelatedTo job link between the original and rework jobs on the Kanban board.\n\n**Customers:** Each return is associated with the customer who returned the goods. Returns can be filtered by customer to see all RMAs for a specific account.\n\n**Sales Orders:** Returns are closely related to the sales order workflow. The returned goods were originally shipped against a sales order, and any replacement or credit may require a new sales order or adjustment.\n\n**Rework Jobs:** When a return requires rework, the system can automatically create a new job with '[Rework]' prefixed to the original job title, assigned to the same track type and operator as the original. The rework job starts at the first stage of the production track and is set to High priority.\n\n### When to Use Customer Returns\n\n- When a customer contacts you about defective or incorrect goods\n- When returned goods arrive at your facility and need to be logged\n- When you need to track the inspection and resolution of quality issues\n- When rework is required and you need to create a linked production job\n- When you need an audit trail of all returns for a specific customer or job\n\n### Access and Permissions\n\nCustomer returns are managed through the API by users with Admin, Manager, or Office Manager roles. The module is currently backend-only — there is no dedicated UI page. Returns are accessed via the `/api/v1/customer-returns` endpoints.","sections":[]}"""
        });

        // ── Process Walkthrough (Article — no UI page) ───────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Customer Returns — Process Walkthrough",
            Slug = "customer-returns-walkthrough",
            Summary = "A conceptual walkthrough of the customer return process: receiving a return, inspection, rework decisions, resolution, and closing.",
            ContentType = TrainingContentType.Article,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 2,
            AppRoutes = """["/sales-orders"]""",
            Tags = """["customer-returns","sales","walkthrough"]""",
            ContentJson = """{"body":"## Customer Returns — Process Walkthrough\n\nThis walkthrough covers the end-to-end process for handling a customer return, from initial receipt through final closure. Since the Customer Returns module is currently backend-only (no dedicated UI page), this guide describes the conceptual workflow and the API operations involved at each step.\n\n### Step 1: Receive the Return\n\nWhen a customer contacts you about returning goods, the first step is to create a return record. This is done via `POST /api/v1/customer-returns` with the following information:\n\n- **Customer** — Select the customer sending the goods back. The CustomerId links the return to their account.\n- **Original Job** — Identify the job that produced the goods being returned. The OriginalJobId establishes traceability.\n- **Reason** — Document why the goods are being returned (required, up to 1000 characters). Be specific: 'Parts out of tolerance on bore diameter' is better than 'Bad parts'.\n- **Notes** — Any additional context (optional, up to 2000 characters). Include PO numbers, quantity returned, shipping details.\n- **Return Date** — When the goods were or will be returned.\n- **Create Rework Job** — If you already know rework is needed, set this to true. The system will automatically create a rework job linked to the original.\n\nThe system generates a unique RMA number (e.g., RMA-00001) and sets the initial status to Received. If a rework job was requested, the status starts at ReworkOrdered instead, and the rework job appears on the Kanban board.\n\n### Step 2: Inspect the Returned Goods\n\nOnce the goods arrive at your facility, they need to be inspected. Update the return via `PUT /api/v1/customer-returns/{id}` to add inspection notes. The entity tracks:\n\n- **InspectedById** — The user who performed the inspection\n- **InspectedAt** — When the inspection occurred\n- **InspectionNotes** — Detailed findings from the inspection (up to 2000 characters)\n\nDocument what you find: measurements, visual defects, comparison to specifications. This inspection record becomes part of the permanent audit trail.\n\n### Step 3: Decide on Corrective Action\n\nBased on the inspection, decide the corrective action:\n\n- **Rework** — If the parts can be corrected, create a rework job (if not already created during Step 1). The rework job is a new production job with '[Rework]' in the title, linked to the same track type as the original, assigned High priority, and connected via a RelatedTo job link.\n- **Replacement** — Create a new sales order and job to produce replacement parts.\n- **Credit** — Issue a credit memo or adjust the invoice for the affected order.\n- **No Action** — If the return is not justified (customer error, shipping damage covered by insurance), document this in the notes.\n\n### Step 4: Resolve the Return\n\nOnce the corrective action is complete (rework finished, replacement shipped, credit issued), resolve the return via `POST /api/v1/customer-returns/{id}/resolve`. This moves the status from whatever current state it is in to Resolved.\n\n**Important rules:**\n- A return that is already Closed cannot be resolved (the system will reject the request)\n- Resolving does not require the return to be in any specific prior status — it can go from Received, UnderInspection, or ReworkOrdered directly to Resolved\n\n### Step 5: Close the Return\n\nAfter the return is resolved and all follow-up is complete, close it via `POST /api/v1/customer-returns/{id}/close`. This is the final, irreversible status.\n\n**Important rules:**\n- Only returns in Resolved status can be closed\n- Closed returns cannot be reopened, resolved again, or modified\n- This ensures a clean audit trail — once closed, the record is final\n\n### Filtering and Reviewing Returns\n\nUse `GET /api/v1/customer-returns` to list all returns. The endpoint supports two filters:\n\n- **customerId** — See all returns for a specific customer\n- **status** — Filter by lifecycle stage (Received, UnderInspection, ReworkOrdered, Resolved, Closed)\n\nResults are ordered by creation date (newest first). Each list item includes the RMA number, customer name, original job number, rework job number (if any), status, reason, return date, and creation timestamp.\n\n### Best Practices\n\n1. **Create returns promptly** — Log the RMA as soon as the customer reports the issue, even before the goods arrive back\n2. **Be specific in reasons** — Vague reasons make it harder to identify patterns and improve quality\n3. **Link rework jobs immediately** — If rework is likely, create the rework job during return creation to get it on the board faster\n4. **Complete inspections thoroughly** — Inspection notes are permanent records used for quality trending\n5. **Don't skip Resolve** — Always resolve before closing to maintain the audit trail\n6. **Review returns by customer** — Periodic review of returns per customer helps identify recurring quality issues","sections":[]}"""
        });

        // ── Field Reference (QuickRef) ───────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Customer Returns Field Reference",
            Slug = "customer-returns-field-reference",
            Summary = "Complete reference for every field, status, API endpoint, validation rule, and action in the Customer Returns module.",
            ContentType = TrainingContentType.QuickRef,
            EstimatedMinutes = 3,
            IsPublished = true,
            SortOrder = 3,
            AppRoutes = """["/sales-orders"]""",
            Tags = """["customer-returns","sales","reference"]""",
            ContentJson = """{"title":"Customer Returns Field Reference","groups":[{"heading":"Entity Fields","items":[{"label":"ReturnNumber (auto-generated)","value":"Format: RMA-XXXXX (e.g., RMA-00001). Sequentially assigned, zero-padded to 5 digits. Cannot be manually set or changed."},{"label":"CustomerId (required)","value":"Foreign key to the Customer entity. Identifies the customer who returned the goods. Must reference an existing, non-deleted customer."},{"label":"OriginalJobId (required)","value":"Foreign key to the Job entity. The production job that created the returned goods. Establishes full traceability from return to original production."},{"label":"ReworkJobId (optional)","value":"Foreign key to the Job entity. Set when a rework job is created (either during return creation with CreateReworkJob=true, or linked later). The rework job title is prefixed with '[Rework]'."},{"label":"Reason (required)","value":"Text, max 1000 characters. Why the goods are being returned. Should be specific and actionable. Validated as non-empty on creation."},{"label":"Notes (optional)","value":"Text, max 2000 characters. Additional context: PO numbers, quantities, shipping details, customer correspondence."},{"label":"Status","value":"Enum: Received, UnderInspection, ReworkOrdered, Resolved, Closed. See Statuses section for lifecycle rules."},{"label":"ReturnDate (required)","value":"DateTimeOffset. When the goods were or will be returned. Set during creation."},{"label":"InspectedById (optional)","value":"Foreign key to ApplicationUser. The user who inspected the returned goods."},{"label":"InspectedAt (optional)","value":"DateTimeOffset. When the inspection was performed."},{"label":"InspectionNotes (optional)","value":"Text, max 2000 characters. Detailed inspection findings: measurements, defect descriptions, root cause analysis."},{"label":"CreatedAt (auto)","value":"DateTimeOffset, set automatically by BaseEntity. When the return record was created."},{"label":"UpdatedAt (auto)","value":"DateTimeOffset, set automatically by BaseEntity. When the return was last modified."},{"label":"CreatedBy (auto)","value":"Set automatically by BaseAuditableEntity. The user who created the return record."}]},{"heading":"Return Statuses","items":[{"label":"Received","value":"Initial status. The return has been logged. Goods may or may not have physically arrived yet. Can transition to any status except Closed directly."},{"label":"UnderInspection","value":"Goods are being inspected. Inspector assigned, findings being documented. Transitional status between Received and a resolution decision."},{"label":"ReworkOrdered","value":"A rework job has been created and linked. Automatically set when CreateReworkJob=true during creation. The rework job appears on the Kanban board."},{"label":"Resolved","value":"Corrective action is complete. Set via POST /{id}/resolve. Cannot be set on a Closed return. Required before closing."},{"label":"Closed","value":"Final, irreversible status. Set via POST /{id}/close. Only Resolved returns can be closed. No further modifications allowed."}]},{"heading":"API Endpoints","items":[{"label":"GET /api/v1/customer-returns","value":"List all returns. Query params: customerId (int, optional), status (CustomerReturnStatus enum, optional). Returns ordered by CreatedAt descending. Response: List<CustomerReturnListItemModel>."},{"label":"GET /api/v1/customer-returns/{id}","value":"Get full detail for a single return. Includes customer name, original job number and title, rework job number, inspector name, inspection timestamps, and all notes. Response: CustomerReturnDetailResponseModel."},{"label":"POST /api/v1/customer-returns","value":"Create a new return. Body: CustomerId, OriginalJobId, Reason, Notes?, ReturnDate, CreateReworkJob (bool). Returns 201 with Location header and CustomerReturnListItemModel."},{"label":"PUT /api/v1/customer-returns/{id}","value":"Update a return's mutable fields. Body: Reason?, Notes?, InspectionNotes?. Only non-null fields are updated (patch semantics). Returns 204."},{"label":"POST /api/v1/customer-returns/{id}/resolve","value":"Move a return to Resolved status. No body required. Fails if return is already Closed. Returns 204."},{"label":"POST /api/v1/customer-returns/{id}/close","value":"Move a return to Closed status. No body required. Fails if return is not in Resolved status. Returns 204."}]},{"heading":"Validation Rules","items":[{"label":"CustomerId","value":"Required. Must be greater than 0. Must reference an existing customer."},{"label":"OriginalJobId","value":"Required. Must be greater than 0. Must reference an existing job."},{"label":"Reason","value":"Required. Cannot be empty. Maximum 1000 characters."},{"label":"Notes","value":"Optional. Maximum 2000 characters."},{"label":"InspectionNotes","value":"Optional. Maximum 2000 characters."},{"label":"Resolve action","value":"Cannot resolve a return that is already Closed. Returns InvalidOperationException (409)."},{"label":"Close action","value":"Only returns in Resolved status can be closed. Returns InvalidOperationException (409)."}]},{"heading":"Rework Job Auto-Creation","items":[{"label":"Trigger","value":"Set CreateReworkJob=true in the POST /api/v1/customer-returns request body."},{"label":"Job Number","value":"Auto-generated (JOB-XXXXX), next sequential number in the system."},{"label":"Title","value":"'[Rework] ' + original job title (e.g., '[Rework] Aluminum Housing Batch 5')."},{"label":"Description","value":"'Rework for RMA {returnNumber}. Reason: {reason}' — includes the RMA number and the return reason."},{"label":"Track Type","value":"Same track type as the original job."},{"label":"Starting Stage","value":"First stage (lowest SortOrder) of the original job's track type."},{"label":"Priority","value":"Always set to High."},{"label":"Assignee","value":"Same assignee as the original job (if any)."},{"label":"Job Link","value":"A RelatedTo link is created between the original job and the rework job."},{"label":"Return Status","value":"Automatically set to ReworkOrdered when a rework job is created."}]},{"heading":"Authorization","items":[{"label":"Required Roles","value":"Admin, Manager, or Office Manager. All endpoints on the controller require one of these roles."},{"label":"Route","value":"/api/v1/customer-returns — all endpoints under this base path."}]},{"heading":"Response Models","items":[{"label":"CustomerReturnListItemModel","value":"Fields: Id, ReturnNumber, CustomerId, CustomerName, OriginalJobId, OriginalJobNumber, ReworkJobId?, ReworkJobNumber?, Status, Reason, ReturnDate, CreatedAt."},{"label":"CustomerReturnDetailResponseModel","value":"Fields: Id, ReturnNumber, CustomerId, CustomerName, OriginalJobId, OriginalJobNumber, OriginalJobTitle, ReworkJobId?, ReworkJobNumber?, Status, Reason, Notes?, ReturnDate, InspectedById?, InspectedByName?, InspectedAt?, InspectionNotes?, CreatedAt, UpdatedAt."}]}]}"""
        });

        // ── Knowledge Check (Quiz) ───────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Customer Returns Knowledge Check",
            Slug = "customer-returns-quiz",
            Summary = "Test your knowledge of the Customer Returns module: RMA lifecycle, statuses, rework jobs, API endpoints, and validation rules.",
            ContentType = TrainingContentType.Quiz,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 4,
            AppRoutes = """["/sales-orders"]""",
            Tags = """["customer-returns","sales","quiz"]""",
            ContentJson = """{"passingScore":80,"questionsPerQuiz":8,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"cr1","text":"A customer calls to report defective parts from a recent order. What is the first step to handle this in QB Engineer?","options":[{"id":"a","text":"Create a new job on the Kanban board titled 'Rework' and assign it to production"},{"id":"b","text":"Create a customer return via POST /api/v1/customer-returns with the customer ID, original job ID, and reason for the return","isCorrect":true},{"id":"c","text":"Open the sales order and change its status to Returned"},{"id":"d","text":"Send the customer a credit memo and close the issue"}],"explanation":"The correct first step is to create a customer return record. This logs the RMA, generates a unique return number, links it to the original job and customer, and starts the return lifecycle at Received status."},{"id":"cr2","text":"What are the five statuses in the customer return lifecycle, in order?","options":[{"id":"a","text":"Open, Inspecting, Reworking, Complete, Archived"},{"id":"b","text":"Received, UnderInspection, ReworkOrdered, Resolved, Closed","isCorrect":true},{"id":"c","text":"Created, Pending, InProgress, Done, Closed"},{"id":"d","text":"Submitted, Reviewed, Approved, Fulfilled, Closed"}],"explanation":"Customer returns follow the lifecycle: Received → UnderInspection → ReworkOrdered → Resolved → Closed. Not every return passes through all statuses — for example, a return may go from Received directly to Resolved if no inspection or rework is needed."},{"id":"cr3","text":"When you create a customer return with CreateReworkJob set to true, what happens automatically?","options":[{"id":"a","text":"The original job is moved back to its first production stage"},{"id":"b","text":"A new job is created with '[Rework]' prefix, High priority, same track type as the original, and a RelatedTo job link is established","isCorrect":true},{"id":"c","text":"The customer receives an automated email notification about the rework"},{"id":"d","text":"The return is automatically resolved since rework has been ordered"}],"explanation":"Setting CreateReworkJob to true creates a new job with '[Rework]' prefixed to the original title, High priority, same track type and assignee, starting at the first stage. A RelatedTo job link connects the original and rework jobs. The return status is set to ReworkOrdered."},{"id":"cr4","text":"You try to close a customer return that is in ReworkOrdered status. What happens?","options":[{"id":"a","text":"The return is closed successfully since all statuses can transition to Closed"},{"id":"b","text":"The system rejects the request because only Resolved returns can be closed","isCorrect":true},{"id":"c","text":"The return is closed but the rework job remains open on the Kanban board"},{"id":"d","text":"The system automatically resolves the return first, then closes it"}],"explanation":"Only returns in Resolved status can be closed. The system enforces this rule — attempting to close a non-resolved return throws an InvalidOperationException. You must first resolve the return via POST /{id}/resolve, then close it via POST /{id}/close."},{"id":"cr5","text":"What format does the system use for automatically generated RMA numbers?","options":[{"id":"a","text":"RET-YYYY-NNNN (year + sequence)"},{"id":"b","text":"RMA-XXXXX (e.g., RMA-00001), sequentially assigned and zero-padded to 5 digits","isCorrect":true},{"id":"c","text":"CR-NNN (simple 3-digit counter)"},{"id":"d","text":"The user manually enters an RMA number during creation"}],"explanation":"RMA numbers follow the format RMA-XXXXX (e.g., RMA-00001, RMA-00042). They are auto-generated by finding the highest existing number and incrementing by one, zero-padded to 5 digits. Users cannot manually set or change the RMA number."},{"id":"cr6","text":"Which roles have access to the customer returns endpoints?","options":[{"id":"a","text":"All authenticated users can view and manage returns"},{"id":"b","text":"Admin, Manager, and Office Manager only","isCorrect":true},{"id":"c","text":"Admin only — returns are a sensitive operation"},{"id":"d","text":"Admin, Manager, Office Manager, PM, and Engineer"}],"explanation":"The CustomerReturnsController is authorized for Admin, Manager, and Office Manager roles. Engineers and Production Workers do not have direct access to customer return management, though they may work on rework jobs that appear on the Kanban board."},{"id":"cr7","text":"You want to see all open returns for a specific customer. How do you query the API?","options":[{"id":"a","text":"GET /api/v1/customer-returns?customerId=42&status=Received to filter by customer and initial status","isCorrect":true},{"id":"b","text":"GET /api/v1/customers/42/returns — returns are nested under the customer endpoint"},{"id":"c","text":"GET /api/v1/customer-returns?search=CustomerName to search by name"},{"id":"d","text":"GET /api/v1/customer-returns and manually filter the response client-side"}],"explanation":"The GET /api/v1/customer-returns endpoint supports two query parameters: customerId (to filter by customer) and status (to filter by lifecycle stage). You can use both together. Results are returned ordered by creation date, newest first."},{"id":"cr8","text":"A return has been inspected and the inspector recorded their findings. Which fields on the entity capture this information?","options":[{"id":"a","text":"InspectorName, InspectionDate, and InspectionResult"},{"id":"b","text":"InspectedById, InspectedAt, and InspectionNotes","isCorrect":true},{"id":"c","text":"ReviewerId, ReviewDate, and ReviewComments"},{"id":"d","text":"Notes field only — there are no dedicated inspection fields"}],"explanation":"The CustomerReturn entity has three dedicated inspection fields: InspectedById (FK to the user who performed the inspection), InspectedAt (when the inspection occurred), and InspectionNotes (detailed findings, up to 2000 characters). These are separate from the general Notes field."},{"id":"cr9","text":"You attempt to resolve a customer return that has already been closed. What is the expected behavior?","options":[{"id":"a","text":"The return is moved back to Resolved status since resolution supersedes closure"},{"id":"b","text":"The system rejects the request because closed returns cannot be resolved","isCorrect":true},{"id":"c","text":"The return is duplicated as a new RMA with Resolved status"},{"id":"d","text":"Nothing happens — the resolve endpoint is idempotent on closed returns"}],"explanation":"The resolve handler explicitly checks: if the return's status is Closed, it throws an InvalidOperationException with 'Cannot resolve a closed return'. Closed is a final, irreversible status — no further status changes are permitted."},{"id":"cr10","text":"When a rework job is automatically created from a customer return, what description does the rework job receive?","options":[{"id":"a","text":"A copy of the original job's description"},{"id":"b","text":"'Rework for RMA {returnNumber}. Reason: {reason}' — including the RMA number and the return reason","isCorrect":true},{"id":"c","text":"'Rework required' with no additional context"},{"id":"d","text":"The description is left blank for the assignee to fill in"}],"explanation":"The auto-created rework job gets a description formatted as 'Rework for RMA {returnNumber}. Reason: {reason}'. For example: 'Rework for RMA RMA-00003. Reason: Parts out of tolerance on bore diameter'. This ensures anyone looking at the rework job on the Kanban board immediately understands its origin and purpose."}]}"""
        });

        Log.Information("Seeded Customer Returns training modules");
    }
}
